// ─── Font Mapping (Alpine system fonts) ────────────────────────────────

const FONT_MAP: Record<string, string> = {
  playfair: 'FreeSerif, DejaVu Serif, serif',
  cormorant: 'Liberation Serif, DejaVu Serif, serif',
  montserrat: 'Liberation Sans, DejaVu Sans, sans-serif',
  raleway: 'FreeSans, DejaVu Sans, sans-serif',
  poppins: 'DejaVu Sans, sans-serif',
  inter: 'Liberation Sans, DejaVu Sans, sans-serif',
};

// ─── Types ─────────────────────────────────────────────────────────────

export interface BrandedQROptions {
  template: string;
  font: string;
  title: string;
  subtitle: string;
  callToAction: string;
  showTableNumber: boolean;
  logoSize: number;
  logoPosition: 'top' | 'center' | 'bottom';
  logoShape: 'original' | 'circle' | 'rounded';
  qrSize: number;
  qrStyle: 'square' | 'rounded' | 'dots';
  showDecorations: boolean;
  format?: 'png' | 'pdf';
  bgColor?: string;
  accentColor?: string;
  textColor?: string;
}

// ─── Helpers ───────────────────────────────────────────────────────────

function escapeXml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;');
}

function tonalliSunSvg(cx: number, cy: number, size: number, color: string, opacity: number): string {
  const r = size / 2;
  const innerR = r * 0.4;
  let rays = '';
  for (let i = 0; i < 12; i++) {
    const angle = (i * 30 * Math.PI) / 180;
    const x1 = cx + Math.cos(angle) * (innerR + 2);
    const y1 = cy + Math.sin(angle) * (innerR + 2);
    const x2 = cx + Math.cos(angle) * r;
    const y2 = cy + Math.sin(angle) * r;
    rays += `<line x1="${x1}" y1="${y1}" x2="${x2}" y2="${y2}" stroke="${color}" stroke-width="2" stroke-linecap="round" opacity="${opacity}"/>`;
  }
  return `
    <circle cx="${cx}" cy="${cy}" r="${innerR}" fill="none" stroke="${color}" stroke-width="2" opacity="${opacity}"/>
    ${rays}
  `;
}

// ─── Main Branded QR Generator ─────────────────────────────────────────

export async function generateBrandedQR(
  slug: string,
  tableNumber: number,
  logoBuffer: Buffer | null,
  options: BrandedQROptions,
): Promise<Buffer> {
  const W = 1200;
  const H = 1800;
  const MARGIN = 60;

  // Resolve template colors with optional overrides
  const tpl = TEMPLATES[options.template] || TEMPLATES['classic-gold'];
  const bg = options.bgColor || tpl.bg;
  const accent = options.accentColor || tpl.accent;
  const text = options.textColor || tpl.text;
  const textMuted = options.textColor || tpl.textMuted;
  const qrDark = tpl.qrDark;
  const qrLight = tpl.qrLight;
  const borderColor = options.accentColor || tpl.borderColor;
  const borderOpacity = tpl.borderOpacity;
  const decoColor = options.accentColor || tpl.decoColor;
  const decoOpacity = tpl.decoOpacity;
  const fontFamily = FONT_MAP[options.font] || FONT_MAP['playfair'];

  // Generate QR code buffer
  const qrPixelSize = Math.round((options.qrSize / 100) * W);
  const url = `${env.MENU_BASE_URL}/${slug}?mesa=${tableNumber}`;
  const qrBuffer = await QRCode.toBuffer(url, {
    width: qrPixelSize,
    margin: 2,
    color: { dark: qrDark, light: qrLight },
    errorCorrectionLevel: 'H',
  });

  // Prepare logo if available
  let logoComposite: { input: Buffer; top: number; left: number } | null = null;
  let logoAreaHeight = 0;

  if (logoBuffer) {
    const logoPixelSize = Math.round((options.logoSize / 100) * W);
    let processedLogo: Buffer;

    if (options.logoShape === 'circle') {
      const circleR = Math.round(logoPixelSize / 2);
      const circleSvg = `<svg width="${logoPixelSize}" height="${logoPixelSize}">
        <circle cx="${circleR}" cy="${circleR}" r="${circleR}" fill="white"/>
      </svg>`;
      processedLogo = await sharp(logoBuffer)
        .resize(logoPixelSize, logoPixelSize, { fit: 'cover' })
        .composite([{ input: Buffer.from(circleSvg), blend: 'dest-in' }])
        .png()
        .toBuffer();
    } else if (options.logoShape === 'rounded') {
      const borderRadius = Math.round(logoPixelSize * 0.15);
      const roundedSvg = `<svg width="${logoPixelSize}" height="${logoPixelSize}">
        <rect width="${logoPixelSize}" height="${logoPixelSize}" rx="${borderRadius}" ry="${borderRadius}" fill="white"/>
      </svg>`;
      processedLogo = await sharp(logoBuffer)
        .resize(logoPixelSize, logoPixelSize, { fit: 'cover' })
        .composite([{ input: Buffer.from(roundedSvg), blend: 'dest-in' }])
        .png()
        .toBuffer();
    } else {
      processedLogo = await sharp(logoBuffer)
        .resize(logoPixelSize, logoPixelSize, { fit: 'inside' })
        .png()
        .toBuffer();
    }

    logoAreaHeight = logoPixelSize + 20;
    const logoLeft = Math.round((W - logoPixelSize) / 2);

    // Logo position will be set after layout calculation
    logoComposite = { input: processedLogo, top: 0, left: logoLeft };
  }

  // ─── Layout calculation ────────────────────────────────────────────
  // Build vertical layout from top to bottom
  let yPos = MARGIN + 40; // Start after top margin + border/decoration space

  // Logo at top
  let logoY = 0;
  if (logoComposite && options.logoPosition === 'top') {
    logoY = yPos;
    yPos += logoAreaHeight;
  }

  // Decorative line after logo
  const decoLine1Y = yPos;
  yPos += 40;

  // Title
  const titleY = yPos + 50;
  const titleFontSize = options.title.length > 30 ? 42 : 52;
  yPos += options.title ? 70 : 0;

  // Subtitle
  const subtitleY = yPos + 30;
  yPos += options.subtitle ? 50 : 0;

  // Logo at center
  if (logoComposite && options.logoPosition === 'center') {
    yPos += 20;
    logoY = yPos;
    yPos += logoAreaHeight;
  }

  // QR code
  yPos += 30;
  const qrY = yPos;
  const qrX = Math.round((W - qrPixelSize) / 2);
  yPos += qrPixelSize + 20;

  // Logo at bottom (between QR and table number)
  if (logoComposite && options.logoPosition === 'bottom') {
    yPos += 10;
    logoY = yPos;
    yPos += logoAreaHeight;
  }

  // Table number
  const tableNumY = yPos + 40;
  yPos += options.showTableNumber ? 60 : 0;

  // Call to action
  const ctaY = yPos + 35;
  yPos += options.callToAction ? 50 : 0;

  // Bottom deco line
  const decoLine2Y = yPos + 20;

  // Tonalli branding - always at bottom
  const brandingY = H - MARGIN - 60;

  // Set logo Y position
  if (logoComposite) {
    logoComposite.top = logoY;
  }

  // ─── Build SVG overlay ──────────────────────────────────────────────
  let svgParts: string[] = [];

  // Background pattern (fun templates)
  if (tpl.svgPattern) {
    svgParts.push(tpl.svgPattern);
  }

  // Corner decorations
  if (options.showDecorations && decoOpacity > 0) {
    const cornerLen = 60;
    const cx1 = MARGIN + 20;
    const cy1 = MARGIN + 20;
    const cx2 = W - MARGIN - 20;
    const cy2 = H - MARGIN - 20;
    const sw = 2;
    const cornerStyle = `stroke="${decoColor}" stroke-width="${sw}" fill="none" opacity="${decoOpacity}"`;

    // Top-left
    svgParts.push(`<line x1="${cx1}" y1="${cy1}" x2="${cx1 + cornerLen}" y2="${cy1}" ${cornerStyle}/>`);
    svgParts.push(`<line x1="${cx1}" y1="${cy1}" x2="${cx1}" y2="${cy1 + cornerLen}" ${cornerStyle}/>`);
    // Top-right
    svgParts.push(`<line x1="${cx2}" y1="${cy1}" x2="${cx2 - cornerLen}" y2="${cy1}" ${cornerStyle}/>`);
    svgParts.push(`<line x1="${cx2}" y1="${cy1}" x2="${cx2}" y2="${cy1 + cornerLen}" ${cornerStyle}/>`);
    // Bottom-left
    svgParts.push(`<line x1="${cx1}" y1="${cy2}" x2="${cx1 + cornerLen}" y2="${cy2}" ${cornerStyle}/>`);
    svgParts.push(`<line x1="${cx1}" y1="${cy2}" x2="${cx1}" y2="${cy2 - cornerLen}" ${cornerStyle}/>`);
    // Bottom-right
    svgParts.push(`<line x1="${cx2}" y1="${cy2}" x2="${cx2 - cornerLen}" y2="${cy2}" ${cornerStyle}/>`);
    svgParts.push(`<line x1="${cx2}" y1="${cy2}" x2="${cx2}" y2="${cy2 - cornerLen}" ${cornerStyle}/>`);
  }

  // Thin border
  if (borderOpacity > 0) {
    svgParts.push(`<rect x="${MARGIN + 10}" y="${MARGIN + 10}" width="${W - MARGIN * 2 - 20}" height="${H - MARGIN * 2 - 20}" rx="4" ry="4" fill="none" stroke="${borderColor}" stroke-width="1" opacity="${borderOpacity}"/>`);
  }

  // Decorative line 1 (after logo / before title)
  if (options.showDecorations && decoOpacity > 0) {
    const lineW = 200;
    const lx = (W - lineW) / 2;
    svgParts.push(`<line x1="${lx}" y1="${decoLine1Y}" x2="${lx + lineW}" y2="${decoLine1Y}" stroke="${decoColor}" stroke-width="1" opacity="${decoOpacity}"/>`);
    // Center diamond
    svgParts.push(`<polygon points="${W / 2 - 5},${decoLine1Y} ${W / 2},${decoLine1Y - 5} ${W / 2 + 5},${decoLine1Y} ${W / 2},${decoLine1Y + 5}" fill="${decoColor}" opacity="${decoOpacity}"/>`);
  }

  // Title
  if (options.title) {
    svgParts.push(`<text x="${W / 2}" y="${titleY}" text-anchor="middle" font-family="${fontFamily}" font-size="${titleFontSize}" font-weight="700" fill="${text}" letter-spacing="3">${escapeXml(options.title)}</text>`);
  }

  // Subtitle
  if (options.subtitle) {
    svgParts.push(`<text x="${W / 2}" y="${subtitleY}" text-anchor="middle" font-family="${fontFamily}" font-size="22" font-weight="400" fill="${textMuted}" letter-spacing="4" text-transform="uppercase">${escapeXml(options.subtitle.toUpperCase())}</text>`);
  }

  // Table number
  if (options.showTableNumber) {
    svgParts.push(`<text x="${W / 2}" y="${tableNumY}" text-anchor="middle" font-family="${fontFamily}" font-size="36" font-weight="700" fill="${accent}" letter-spacing="6">${escapeXml(`MESA ${tableNumber}`)}</text>`);
  }

  // Call to action
  if (options.callToAction) {
    svgParts.push(`<text x="${W / 2}" y="${ctaY}" text-anchor="middle" font-family="${fontFamily}" font-size="20" fill="${textMuted}" letter-spacing="1">${escapeXml(options.callToAction)}</text>`);
  }

  // Decorative line 2 (bottom)
  if (options.showDecorations && decoOpacity > 0) {
    const lineW = 200;
    const lx = (W - lineW) / 2;
    svgParts.push(`<line x1="${lx}" y1="${decoLine2Y}" x2="${lx + lineW}" y2="${decoLine2Y}" stroke="${decoColor}" stroke-width="1" opacity="${decoOpacity}"/>`);
  }

  // Tonalli branding (always present, subtle)
  const brandOpacity = 0.35;
  svgParts.push(tonalliSunSvg(W / 2 - 70, brandingY + 10, 20, textMuted, brandOpacity));
  svgParts.push(`<text x="${W / 2 - 45}" y="${brandingY + 16}" text-anchor="start" font-family="Liberation Sans, DejaVu Sans, sans-serif" font-size="16" font-weight="700" fill="${textMuted}" opacity="${brandOpacity}" letter-spacing="3">TONALLI</text>`);
  svgParts.push(`<text x="${W / 2}" y="${brandingY + 40}" text-anchor="middle" font-family="Liberation Sans, DejaVu Sans, sans-serif" font-size="13" fill="${textMuted}" opacity="${brandOpacity * 0.8}">tonalli.app</text>`);

  const overlaySvg = `<svg width="${W}" height="${H}" xmlns="http://www.w3.org/2000/svg">
    ${svgParts.join('\n    ')}
  </svg>`;

  // ─── Compose final image ────────────────────────────────────────────
  const composites: sharp.OverlayOptions[] = [];

  // SVG overlay with text, decorations, branding
  composites.push({ input: Buffer.from(overlaySvg), top: 0, left: 0 });

  // QR code
  composites.push({ input: qrBuffer, top: qrY, left: qrX });

  // Logo
  if (logoComposite) {
    composites.push({
      input: logoComposite.input,
      top: logoComposite.top,
      left: logoComposite.left,
    });
  }

  // Create base image with background color
  const pngBuffer = await sharp({
    create: {
      width: W,
      height: H,
      channels: 4,
      background: hexToRgba(bg),
    },
  })
    .composite(composites)
    .png({ quality: 100 })
    .toBuffer();

  return pngBuffer;
}

// ─── PDF Wrapper ───────────────────────────────────────────────────────

export async function wrapInPdf(pngBuffer: Buffer, width: number, height: number): Promise<Buffer> {
  return new Promise((resolve, reject) => {
    // Convert pixels to points (72 DPI)
    const ptW = (width / 300) * 72;
    const ptH = (height / 300) * 72;

    const doc = new PDFDocument({ size: [ptW, ptH], margin: 0 });
    const chunks: Buffer[] = [];

    doc.on('data', (chunk: Buffer) => chunks.push(chunk));
    doc.on('end', () => resolve(Buffer.concat(chunks)));
    doc.on('error', reject);

    doc.image(pngBuffer, 0, 0, { width: ptW, height: ptH });
    doc.end();
  });
}

// ─── Color helper ──────────────────────────────────────────────────────

function hexToRgba(hex: string): { r: number; g: number; b: number; alpha: number } {
  const h = hex.replace('#', '');
  return {
    r: parseInt(h.substring(0, 2), 16),
    g: parseInt(h.substring(2, 4), 16),
    b: parseInt(h.substring(4, 6), 16),
    alpha: 1,
  };
}
